//! embed-text — REAL contextual word embeddings from a qwen forward pass (not the token table).
//!
//! The token-embedding table is non-semantic (nearest-neighbour gives orthographic noise). The
//! contextual hidden state after a forward pass IS semantic. For each word we tokenize (greedy
//! byte-level over the qwen vocab JSON), run `forward_one` per token through `NativeLlamaPipeline`,
//! and mean-pool `get_last_residual()` (the post-block residual) into one vector. A fresh pipeline
//! per word avoids KV-cache bleed (there is no reset method). Output: `{ word: [f32; hidden] }` JSON.
//!
//!   monster-build --gnosis-native-apps distributed-inference --bin embed-text
//!   ./embed-text ocean sea banana fear terror   # EMBED_KNOT, EMBED_VOCAB override the defaults
//!
//! Verifies the contextual claim: cos(ocean,sea) > cos(ocean,banana), cos(fear,terror) > cos(fear,banana).

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;
use std::collections::HashMap;
use std::fs;

fn load_vocab(path: &str) -> Result<HashMap<String, u32>, String> {
    let s = fs::read_to_string(path).map_err(|e| format!("vocab read {}: {}", path, e))?;
    let v: serde_json::Value = serde_json::from_str(&s).map_err(|e| format!("vocab json: {}", e))?;
    let obj = v.get("vocab").and_then(|x| x.as_object()).ok_or("vocab json has no .vocab object")?;
    let mut m = HashMap::with_capacity(obj.len());
    for (k, val) in obj {
        if let Some(id) = val.as_u64() {
            m.insert(k.clone(), id as u32);
        }
    }
    Ok(m)
}

/// GPT-2 byte-level: prepend the word-start marker 'Ġ' (U+0120), greedy longest-prefix match.
fn tokenize(word: &str, vocab: &HashMap<String, u32>) -> Vec<u32> {
    let mut s: String = format!("\u{0120}{}", word.to_lowercase());
    let mut ids = Vec::new();
    while !s.is_empty() {
        let chars: Vec<char> = s.chars().collect();
        let maxlen = chars.len().min(24);
        let mut matched = false;
        for len in (1..=maxlen).rev() {
            let prefix: String = chars[..len].iter().collect();
            if let Some(&id) = vocab.get(&prefix) {
                ids.push(id);
                s = chars[len..].iter().collect();
                matched = true;
                break;
            }
        }
        if !matched {
            s = chars[1..].iter().collect();
        }
    }
    ids
}

fn arg(flag: &str) -> Option<String> {
    let a: Vec<String> = std::env::args().collect();
    a.iter().position(|x| x == flag).and_then(|i| a.get(i + 1).cloned())
}

fn main() -> Result<(), String> {
    let words_file = arg("--words");
    let out_file = arg("--out");
    // word list: from --words FILE (one per line) or positional args.
    let words: Vec<String> = if let Some(ref f) = words_file {
        fs::read_to_string(f)
            .map_err(|e| format!("words read {}: {}", f, e))?
            .split_whitespace()
            .map(|s| s.to_string())
            .collect()
    } else {
        std::env::args().skip(1).filter(|a| !a.starts_with("--")).collect()
    };
    if words.is_empty() {
        return Err("usage: embed-text <word ...>  |  --words FILE --out FILE".to_string());
    }
    let knot_path = std::env::var("EMBED_KNOT").unwrap_or_else(|_| "/tmp/qwen-coder-7b.knot".to_string());
    let vocab_path = std::env::var("EMBED_VOCAB")
        .unwrap_or_else(|_| "apps/edge-workers/vocab-cache/qwen3-8b-temp-vocab.json".to_string());
    let vocab = load_vocab(&vocab_path)?;
    eprintln!("[embed-text] vocab {} entries; knot {}; {} words", vocab.len(), knot_path, words.len());

    // Load the model ONCE; reset_context() between words (KV slots get overwritten). ~100x faster
    // than reloading the 4.68GB knot per word — makes a real batch tractable.
    let knot = KnotWeights::load(&knot_path).map_err(|e| format!("knot load: {:?}", e))?;
    let mut pipe = NativeLlamaPipeline::from_knot(knot, false, 0.8);
    let hidden = pipe.hidden_dim();

    let mut out = serde_json::Map::new();
    let total = words.len();
    for (wi, word) in words.iter().enumerate() {
        let toks = tokenize(word, &vocab);
        if toks.is_empty() {
            continue;
        }
        pipe.reset_context();
        let mut acc = vec![0f32; hidden];
        for (pos, &tok) in toks.iter().enumerate() {
            pipe.forward_one(tok as usize, pos, false)
                .map_err(|e| format!("forward_one({}, {}): {}", tok, pos, e))?;
            let r = pipe.get_x_residual();
            for i in 0..hidden {
                acc[i] += r[i];
            }
        }
        let n = toks.len() as f32;
        for x in acc.iter_mut() {
            *x = (*x / n * 100000.0).round() / 100000.0;
        }
        out.insert(word.clone(), serde_json::json!(acc));
        if (wi + 1) % 100 == 0 || wi + 1 == total {
            eprintln!("[embed-text] {}/{} embedded", wi + 1, total);
        }
    }
    let json = serde_json::to_string(&serde_json::Value::Object(out)).map_err(|e| e.to_string())?;
    if let Some(f) = out_file {
        fs::write(&f, &json).map_err(|e| format!("out write {}: {}", f, e))?;
        eprintln!("[embed-text] wrote {} embeddings → {}", total, f);
    } else {
        println!("{}", json);
    }
    Ok(())
}
